using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingDbContext : DbContext
{
    public DbSet<Event> Events { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Configure your database connection string here
        optionsBuilder.UseSqlServer("YourConnectionString");
    }
}

public class Event
{
    public int Id { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketService
{
    private readonly EventBookingDbContext _dbContext;

    public TicketService(EventBookingDbContext dbContext)
    {
        _dbContext = dbContext;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var @event = await _dbContext.Events
            .FirstOrDefaultAsync(e => e.Id == eventId);

        if (@event == null || quantity <= 0 || @event.AvailableSeats < quantity)
        {
            return false; // Event not found or insufficient seats
        }

        using (var transaction = await _dbContext.Database.BeginTransactionAsync())
        {
            try
            {
                var updatedEvent = new Event
                {
                    Id = @event.Id,
                    AvailableSeats = @event.AvailableSeats - quantity
                };

                _dbContext.Entry(@event).CurrentValues.SetValues(updatedEvent);

                await _dbContext.SaveChangesAsync();
                await transaction.CommitAsync();

                return true;
            }
            catch (Exception)
            {
                await transaction.RollbackAsync();
                throw; // Rethrow to handle exception in the caller
            }
        }
    }
}